<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<title>Falling Sand Sandbox</title>
<style>
  :root {
    --bg: #0d0f14;
    --panel: #171a22;
    --panel-border: #2a2e3a;
    --text: #e6e8ee;
    --accent: #4fa3ff;
  }
  * { box-sizing: border-box; }
  html, body {
    margin: 0;
    height: 100%;
    background: var(--bg);
    color: var(--text);
    font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, sans-serif;
  }
  body {
    display: flex;
    flex-direction: column;
    align-items: center;
    justify-content: center;
    gap: 16px;
    padding: 24px;
    min-height: 100vh;
  }
  h1 {
    font-size: 18px;
    font-weight: 600;
    letter-spacing: 0.04em;
