<body>
  <h1>FALLING SAND SANDBOX</h1>
  <div id="panel">
    <div id="toolbar">
      <button class="mat-btn active" id="mat-sand" data-mat="sand"><span class="swatch" style="background:#d9a441"></span>Sand</button>
      <button class="mat-btn" id="mat-water" data-mat="water"><span class="swatch" style="background:#3aa0ff"></span>Water</button>
      <button class="mat-btn" id="mat-wall" data-mat="wall"><span class="swatch" style="background:#888c99"></span>Wall</button>
      <button class="mat-btn" id="mat-acid" data-mat="acid"><span class="swatch" style="background:#7CFF3A"></span>Acid</button>
      <button class="mat-btn" id="mat-empty" data-mat="empty"><span class="swatch" style="background:#0a0c10;border-style:dashed"></span>Eraser</button>
      <button id="clear">Clear All</button>
    </div>
    <div id="canvas-wrap">
      <canvas id="sand" width="500" height="500"></canvas>
    </div>
    <div id="hint">Click and drag on the canvas to paint. Choose a material above.</div>
  </div>

<script>
(function () {
  "use strict";

  const W = 100, H = 100;      // grid cells
  const CELL = 5;               // px per cell -> 500x500 canvas
  const EMPTY = "empty", SAND = "sand", WATER = "water", WALL = "wall", ACID = "acid";

  const canvas = document.getElementById("sand");
  const ctx = canvas.getContext("2d");

  const colors = {
    empty: "#0a0c10",
    sand:  "#d9a441",
    water: "#3aa0ff",
    wall:  "#888c99",
    acid:  "#7CFF3A"
  };

  let grid = new Array(W * H).fill(EMPTY);

  function index(x, y) { return y * W + x; }
  function inBounds(x, y) { return x >= 0 && x < W && y >= 0 && y < H; }

  function getCell(x, y) {
    if (!inBounds(x, y)) return WALL;
    return grid[index(x, y)];
  }
  function setCell(x, y, mat) {
    if (!inBounds(x, y)) return;
    grid[index(x, y)] = mat;
  }

  // ---- simulation step ----
  function stepSand(x, y, moved) {
    const idx = index(x, y);
    const by = y + 1;
    if (!inBounds(x, by)) return; // bottom boundary: rest
    const bidx = index(x, by);
    const bmat = grid[bidx];

    if (bmat === EMPTY) {
      grid[bidx] = SAND; grid[idx] = EMPTY;
      moved[idx] = 1; moved[bidx] = 1;
      return;
    }

    if (bmat === WATER || bmat === ACID) {
      const dirs = Math.random() < 0.5 ? [-1, 1] : [1, -1];

      // 1) try to push the liquid sideways (around the falling sand), from the liquid's own row
      for (const dx of dirs) {
        const lx = x + dx, ly = by;
        if (inBounds(lx, ly)) {
          const lidx = index(lx, ly);
          if (grid[lidx] === EMPTY && !moved[lidx]) {
            grid[lidx] = bmat; moved[lidx] = 1;
            grid[bidx] = SAND; grid[idx] = EMPTY;
            moved[idx] = 1; moved[bidx] = 1;
            return;
          }
        }
      }
      // 2) try to push the liquid diagonally further down (still local, never upward)
      for (const dx of dirs) {
        const lx = x + dx, ly = by + 1;
        if (inBounds(lx, ly)) {
          const lidx = index(lx, ly);
          if (grid[lidx] === EMPTY && !moved[lidx]) {
            grid[lidx] = bmat; moved[lidx] = 1;
            grid[bidx] = SAND; grid[idx] = EMPTY;
            moved[idx] = 1; moved[bidx] = 1;
            return;
          }
        }
      }
      // 3) try sliding the sand diagonally instead
      for (const dx of dirs) {
        const nx = x + dx, ny = y + 1;
        if (inBounds(nx, ny)) {
          const nidx = index(nx, ny);
          if (grid[nidx] === EMPTY && !moved[nidx]) {
            grid[nidx] = SAND; grid[idx] = EMPTY;
            moved[idx] = 1; moved[nidx] = 1;
            return;
          }
        }
      }
      // 4) last resort: plain sink-swap (sand still must be able to sink)
      grid[bidx] = SAND; grid[idx] = bmat;
      moved[idx] = 1; moved[bidx] = 1;
      return;
    }

    // blocked by sand/wall below -> try diagonal slide
    const dirs2 = Math.random() < 0.5 ? [-1, 1] : [1, -1];
    for (const dx of dirs2) {
      const nx = x + dx, ny = y + 1;
      if (inBounds(nx, ny)) {
        const nidx = index(nx, ny);
        if (grid[nidx] === EMPTY && !moved[nidx]) {
          grid[nidx] = SAND; grid[idx] = EMPTY;
          moved[idx] = 1; moved[nidx] = 1;
          return;
        }
      }
    }
    // otherwise rest
  }

  function stepLiquid(x, y, moved, mat) {
    const idx = index(x, y);
    const by = y + 1;

    if (inBounds(x, by)) {
      const bidx = index(x, by);
      if (grid[bidx] === EMPTY) {
        grid[bidx] = mat; grid[idx] = EMPTY;
        moved[idx] = 1; moved[bidx] = 1;
        return;
      }
    }

    const dirs = Math.random() < 0.5 ? [-1, 1] : [1, -1];
    // diagonal down
    for (const dx of dirs) {
      const nx = x + dx, ny = y + 1;
      if (inBounds(nx, ny)) {
        const nidx = index(nx, ny);
        if (grid[nidx] === EMPTY && !moved[nidx]) {
          grid[nidx] = mat; grid[idx] = EMPTY;
          moved[idx] = 1; moved[nidx] = 1;
          return;
        }
      }
    }
    // horizontal spread
    for (const dx of dirs) {
      const nx = x + dx, ny = y;
      if (inBounds(nx, ny)) {
        const nidx = index(nx, ny);
        if (grid[nidx] === EMPTY && !moved[nidx]) {
          grid[nidx] = mat; grid[idx] = EMPTY;
          moved[idx] = 1; moved[nidx] = 1;
          return;
        }
      }
    }
    // rest
  }

  function stepAcid(x, y, moved) {
    const idx = index(x, y);
    const candidates = [];
    if (inBounds(x, y + 1)) candidates.push([x, y + 1]);
    if (inBounds(x - 1, y)) candidates.push([x - 1, y]);
    if (inBounds(x + 1, y)) candidates.push([x + 1, y]);

    // randomize order so left/right/below dissolve isn't biased
    for (let i = candidates.length - 1; i > 0; i--) {
      const j = Math.floor(Math.random() * (i + 1));
      [candidates[i], candidates[j]] = [candidates[j], candidates[i]];
    }

    for (const [tx, ty] of candidates) {
      const tidx = index(tx, ty);
      const tmat = grid[tidx];
      if (tmat === SAND || tmat === WALL) {
        grid[tidx] = EMPTY;   // dissolved
        moved[tidx] = 1;
        grid[idx] = EMPTY;    // acid consumed
        moved[idx] = 1;
        return;
      }
    }

    stepLiquid(x, y, moved, ACID);
  }

  function step() {
    const moved = new Uint8Array(W * H);
    for (let y = H - 1; y >= 0; y--) {
      for (let x = 0; x < W; x++) {
        const idx = index(x, y);
        if (moved[idx]) continue;
        const mat = grid[idx];
        if (mat === EMPTY || mat === WALL) continue;
        if (mat === SAND) stepSand(x, y, moved);
        else if (mat === WATER) stepLiquid(x, y, moved, WATER);
        else if (mat === ACID) stepAcid(x, y, moved);
      }
    }
  }

  // ---- rendering ----
  function render() {
    ctx.fillStyle = colors.empty;
    ctx.fillRect(0, 0, canvas.width, canvas.height);
    for (let y = 0; y < H; y++) {
      for (let x = 0; x < W; x++) {
        const mat = grid[index(x, y)];
        if (mat === EMPTY) continue;
        ctx.fillStyle = colors[mat];
        ctx.fillRect(x * CELL, y * CELL, CELL, CELL);
      }
    }
  }

  // ---- public API ----
  window.sim = {
    w: W,
    h: H,
    tick(n) {
      n = n || 1;
      for (let i = 0; i < n; i++) step();
    },
    get(x, y) {
      if (!inBounds(x, y)) return WALL;
      return grid[index(x, y)];
    },
    set(x, y, material) {
      if (!inBounds(x, y)) return;
      if (![EMPTY, SAND, WATER, WALL, ACID].includes(material)) return;
      grid[index(x, y)] = material;
    },
    clear() {
      grid = new Array(W * H).fill(EMPTY);
    }
  };

  // ---- UI wiring ----
  let currentMat = SAND;
  const buttons = document.querySelectorAll(".mat-btn");
  buttons.forEach(btn => {
    btn.addEventListener("click", () => {
      currentMat = btn.dataset.mat;
      buttons.forEach(b => b.classList.remove("active"));
      btn.classList.add("active");
    });
  });

  document.getElementById("clear").addEventListener("click", () => {
    window.sim.clear();
  });

  let painting = false;
  const BRUSH_RADIUS = 2;

  function paintAt(clientX, clientY) {
    const rect = canvas.getBoundingClientRect();
    const scaleX = canvas.width / rect.width;
    const scaleY = canvas.height / rect.height;
    const px = (clientX - rect.left) * scaleX;
    const py = (clientY - rect.top) * scaleY;
    const cx = Math.floor(px / CELL);
    const cy = Math.floor(py / CELL);

    for (let dy = -BRUSH_RADIUS; dy <= BRUSH_RADIUS; dy++) {
      for (let dx = -BRUSH_RADIUS; dx <= BRUSH_RADIUS; dx++) {
        if (dx * dx + dy * dy > BRUSH_RADIUS * BRUSH_RADIUS) continue;
        const x = cx + dx, y = cy + dy;
        if (inBounds(x, y)) grid[index(x, y)] = currentMat;
      }
    }
  }

  canvas.addEventListener("mousedown", (e) => {
    painting = true;
    paintAt(e.clientX, e.clientY);
  });
  window.addEventListener("mousemove", (e) => {
    if (painting) paintAt(e.clientX, e.clientY);
  });
  window.addEventListener("mouseup", () => { painting = false; });
  canvas.addEventListener("mouseleave", () => { /* keep painting if button held */ });

  // touch support
  canvas.addEventListener("touchstart", (e) => {
    painting = true;
    const t = e.touches[0];
    paintAt(t.clientX, t.clientY);
    e.preventDefault();
  }, { passive: false });
  canvas.addEventListener("touchmove", (e) => {
    if (painting) {
      const t = e.touches[0];
      paintAt(t.clientX, t.clientY);
    }
    e.preventDefault();
  }, { passive: false });
  window.addEventListener("touchend", () => { painting = false; });

  // ---- main loop ----
  function loop() {
    window.sim.tick(1);
    render();
    requestAnimationFrame(loop);
  }
  requestAnimationFrame(loop);
})();
</script>
</body>
</html>
